3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (isAlive: boolean, neighbors: number): boolean =>
12	  neighbors === 3 || (isAlive && neighbors === 2);
13	
14	function countNeighbors(cells: Cell[]): Map<string, { cell: Cell; count: number }> {
15	  const counts = new Map<string, { cell: Cell; count: number }>();
16	  for (const [x, y] of cells) {
17	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
18	      const neighbor: Cell = [x + dx, y + dy];
19	      const key = cellKey(neighbor);
20	      const entry = counts.get(key);
21	      if (entry) entry.count++;
22	      else counts.set(key, { cell: neighbor, count: 1 });
23	    }
24	  }
25	  return counts;
26	}
