28	export function nextGeneration(cells: Cell[]): Cell[] {
29	  const aliveKeys = new Set(cells.map(cellKey));
30	  const neighborCounts = countNeighbors(cells);
31	
32	  const nextCells: Cell[] = [];
33	  for (const [key, { cell, count }] of neighborCounts) {
34	    if (survives(aliveKeys.has(key), count)) nextCells.push(cell);
35	  }
36	  return nextCells;
37	}
